--
-- Table structure for table `db_class_schedules`
--

DROP TABLE IF EXISTS `db_class_schedules`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `db_class_schedules` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `area_code` varchar(15) DEFAULT NULL,
  `period_id` int(11) DEFAULT NULL,
  `college_id` int(11) DEFAULT NULL,
  `course_id` int(11) DEFAULT NULL,
  `term` varchar(8) DEFAULT NULL,
  `ay` varchar(9) DEFAULT NULL,
  `schedule_code` varchar(12) DEFAULT NULL,
  `subject_id` int(11) DEFAULT NULL,
  `instructor_id` int(11) DEFAULT NULL,
  `year_level` varchar(10) DEFAULT NULL,
  `is_with_lec` varchar(1) DEFAULT 'Y',
  `lec_week_day` varchar(5) DEFAULT NULL,
  `lec_start_time` time DEFAULT NULL,
  `lec_end_time` time DEFAULT NULL,
  `lec_room_id` int(11) DEFAULT NULL,
  `is_with_lab` varchar(1) DEFAULT NULL,
  `lab_week_day` varchar(5) DEFAULT NULL,
  `lab_start_time` time DEFAULT NULL,
  `lab_end_time` time DEFAULT NULL,
  `lab_room_id` int(11) DEFAULT NULL,
  `section_id` int(11) DEFAULT NULL,
  `class_size` int(11) DEFAULT 0,
  `class_size_ireg` int(11) DEFAULT 0,
  `class_max_size` int(11) DEFAULT 35,
  `class_ext_size` int(11) DEFAULT 5,
  `is_dissolved` varchar(1) DEFAULT 'N',
  `is_merged` varchar(1) DEFAULT 'N',
  `merged_class_id` varchar(100) DEFAULT NULL,
  `is_parent_merged` varchar(1) DEFAULT 'N',
  `is_with_complete_entry` varchar(1) DEFAULT 'N',
  `is_approved_grade` varchar(1) DEFAULT 'N',
  `is_approved_grade_entry` varchar(1) DEFAULT 'N',
  `is_class_list_check` varchar(1) DEFAULT 'N',
  `is_creditable` varchar(1) DEFAULT 'Y',
  `is_shared_faculty` varchar(1) DEFAULT 'N',
  `shared_faculty_id` varchar(100) DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `with_complete_entry_at` timestamp NULL DEFAULT NULL,
  `approved_entry_at` timestamp NULL DEFAULT NULL,
  `undo_approved_at` timestamp NULL DEFAULT NULL,
  `undo_approved_entry_at` timestamp NULL DEFAULT NULL,
  `is_class_list_check_at` timestamp NULL DEFAULT NULL,
  `with_complete_entry_user_id` int(11) DEFAULT NULL,
  `approved_grade_user_id` int(11) DEFAULT NULL,
  `approved_grade_entry_user_id` int(11) DEFAULT NULL,
  `undo_approved_grade_user_id` int(11) DEFAULT NULL,
  `undo_approved_grade_entry_user_id` int(11) DEFAULT NULL,
  `is_class_list_check_user_id` int(11) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `merged_at` timestamp NULL DEFAULT NULL,
  `unmerged_all_at` timestamp NULL DEFAULT NULL,
  `unmergedfromparent_at` timestamp NULL DEFAULT NULL,
  `noncredit_at` timestamp NULL DEFAULT NULL,
  `undononcredit_at` timestamp NULL DEFAULT NULL,
  `created_user_id` int(11) DEFAULT NULL,
  `updated_user_id` int(11) DEFAULT NULL,
  `deleted_user_id` int(11) DEFAULT NULL,
  `merged_user_id` int(11) DEFAULT NULL,
  `unmerged_all_user_id` int(11) DEFAULT NULL,
  `unmergedfromparent_user_id` int(11) DEFAULT NULL,
  `noncredit_user_id` int(11) DEFAULT NULL,
  `undononcredit_user_id` int(11) DEFAULT NULL,
  KEY `id` (`id`),
  KEY `idx_class_schedules_filtering` (`area_code`,`college_id`,`course_id`,`term`,`ay`,`deleted_at`),
  KEY `idx_class_schedule` (`area_code`,`college_id`,`course_id`,`term`,`ay`,`year_level`)
) ENGINE=InnoDB AUTO_INCREMENT=28452 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
