DROP TABLE IF EXISTS `db_courses`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `db_courses` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `area_code` varchar(15) DEFAULT NULL,
  `category` varchar(15) DEFAULT NULL,
  `class_id` int(11) DEFAULT NULL,
  `course_program` varchar(25) DEFAULT NULL,
  `status` varchar(15) DEFAULT NULL,
  `code` varchar(11) DEFAULT NULL,
  `name` varchar(255) DEFAULT NULL,
  `major_id` int(11) DEFAULT NULL,
  `is_parent` varchar(1) DEFAULT 'N',
  `parent_id` int(11) DEFAULT NULL,
  `aop` varchar(255) DEFAULT NULL,
  `calendar` varchar(15) DEFAULT NULL,
  `no_years` int(11) DEFAULT NULL,
  `no_of_terms` int(11) DEFAULT 3,
  `year_offered` varchar(4) DEFAULT NULL,
  `max_unit` int(11) DEFAULT NULL,
  `lab_units` decimal(18,2) DEFAULT 0.00,
  `lec_units` decimal(18,2) DEFAULT 0.00,
  `tot_units` decimal(18,2) DEFAULT 0.00,
  `tution_per_unit` decimal(18,2) DEFAULT 0.00,
  `fee_amount` decimal(18,2) DEFAULT 0.00,
  `level_id` int(11) DEFAULT NULL,
  `college_id` int(11) DEFAULT NULL,
  `is_ched_priority` varchar(1) DEFAULT 'Y',
  `is_thesis_dissertation_required` varchar(15) DEFAULT NULL,
  `is_degree` varchar(1) DEFAULT NULL,
  `is_undergrad` varchar(1) DEFAULT NULL,
  `is_advanced_educ` varchar(1) DEFAULT 'N',
  `filename` mediumtext DEFAULT NULL,
  `remarks` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  `created_user_id` int(11) DEFAULT NULL,
  `updated_user_id` int(11) DEFAULT NULL,
  `deleted_user_id` int(11) DEFAULT NULL,
  KEY `id` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=925 DEFAULT CHARSET=latin1 COLLATE=latin1_swedish_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

